using System;
using System.Data.SqlClient;
using System.Linq;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;

public static class ReportingAPI
{
    private static string connectionString;

    public static void Run(HttpRequest req, ILogger log, IMapper mapper, IConfiguration config)
    {
        connectionString = config["ConnectionStrings:ReportingDB"];

        var queryParameters = HttpContext.Current.Request.QueryString;
        var query = $"SELECT * FROM Orders WHERE 1=1";

        if (queryParameters != null)
        {
            foreach (var keyValuePair in queryParameters)
            {
                switch (keyValuePair.Key)
                {
                    case "customerId":
                        query += $" AND CustomerID = '{keyValuePair.Value}'";
                        break;
                    case "orderDateFrom":
                        query += $" AND OrderDate >= '{keyValuePair.Value}'";
                        break;
                    case "orderDateTo":
                        query += $" AND OrderDate <= '{keyValuePair.Value}'";
                        break;
                    // Add more filtering options here as needed...
                }
            }
        }

        var sqlConnection = new SqlConnection(connectionString);
        sqlConnection.Open();

        using (var command = new SqlCommand(query, sqlConnection))
        {
            using (var reader = command.ExecuteReader())
            {
                var orders = new List<Order>();
                while (reader.Read())
                {
                    orders.Add(mapper.Map<Order>(reader));
                }

                var result = new ObjectResult(orders);
                result.StatusCode = StatusCodes.Status200OK;
                req.Results.Add(result);
            }
        }
    }
}